uctor() {\n      this.timer = null;\n      this.scrollRateChange = this.throttled(this.handleScrollChange, 1000);\n    }\n\n    \n    throttled(fn, delay) {\n      let starttime = Date.now();\n      return function () {\n      console.log('throttled')\n        let curTime = Date.now();\n        let remaining = delay - (curTime - starttime);\n        let context = this;\n        let args = arguments;\n        clearTimeout(this.timer);\n        if (remaining <= 0) {\n          fn.apply(context, args);\n          starttime = Date.now();\n        } else {\n          this.timer = setTimeout(() => fn.apply(context, args), remaining);\n        }\n      };\n    }\n\n    \n    handleScrollChange() {\n      console.log('handleScrollChange')\n      const height = document.documentElement.scrollHeight; \n      const totalHeight =\n        window.innerHeight || document.documentElement.clientHeight;\n      sendTeaEvent('lark_website_rate_show_view', {\n        rate: Math.round((window.scrollY / (height - totalHeight)) * 100) / 100,\n        height: totalHeight,\n      });\n    }\n\n    \n    handleScroll() {\n      this.scrollRateChange();\n    }\n\n    \n    start() {\n      console.log('start')\n      window.addEventListener('scroll', this.handleScroll.bind(this));\n    }\n\n    \n    stop() {\n      window.removeEventListener('scroll', this.handleScroll.bind(this));\n    }\n  }\n\n  new PageEventTracker().start();\n})();\n</script>\n</body>\n</html>	Lark | Productivity Superapp for Chat, Meetings, Docs &amp; Projects	{"length":68,"title":"Lark | Productivity Superapp for Chat, Meetings, Docs &amp; Projects"}	\N	2026-06-28 11:48:46	1	2026-06-28 11:48:44	2026-06-28 11:48:46
